/**
 * Returns a list of all government schemes in the knowledge base
 * @summary List all available policy schemes
 */
export const getListSchemesUrl = (params?: ListSchemesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/policy/schemes?${stringifiedParams}`
    : `/api/policy/schemes`;
};

